  9→// Database file location
 10→const DB_PATH = config.dbPath;
 11→
 12→// Global database instance
 13→let db: Database.Database | null = null;
 14→
 15→/**
 16→ * Get or create database connection
 17→ */
 18→export function getDatabase(): Database.Database {
 19→  if (!db) {
 20→    ensureDirExists(dirname(DB_PATH));
 21→    db = new Database(DB_PATH);
 22→    
 23→    // Enable WAL mode for better concurrent access
 24→    db.pragma('journal_mode = WAL');
 25→    db.pragma('synchronous = NORMAL');
 26→    db.pragma('cache_size = 1000');
 27→    db.pragma('foreign_keys = ON');
 28→    
 29→    // Initialize schema if needed
 30→    initializeSchema();
 31→  }
 32→  
 33→  return db;
 34→}
 35→
 36→/**
 37→ * Initialize database schema via migrations
 38→ */
 39→let webhookListenerInitialized = false;
 40→
 41→function initializeSchema() {
 42→  if (!db) return;
 43→  try {
 44→    runMigrations(db);
 45→    seedAdminUserFromEnv(db);
 46→
 47→    // Initialize webhook event listener (once)
 48→    if (!webhookListenerInitialized) {
 49→      webhookListenerInitialized = true;
 50→      import('./webhooks').then(({ initWebhookListener }) => {
 51→        initWebhookListener();
 52→      }).catch(() => {
 53→        // Silent - webhooks are optional
 54→      });
 55→
 56→      // Start built-in scheduler for auto-backup and auto-cleanup.
 57→      // Avoid running background jobs during `next build` static generation.
 58→      if (process.env.NEXT_PHASE !== 'phase-production-build') {
 59→        import('./scheduler').then(({ initScheduler }) => {
 60→          initScheduler();
 61→        }).catch(() => {
 62→          // Silent - scheduler is optional
 63→        });
 64→      }
 65→    }
 66→
 67→    logger.info('Database migrations applied successfully');
 68→  } catch (error) {
 69→    logger.error({ err: error }, 'Failed to apply database migrations');
 70→    throw error;
 71→  }
 72→}
 73→
 74→interface CountRow { count: number }
 75→
 76→function seedAdminUserFromEnv(dbConn: Database.Database): void {
 77→  // Skip seeding during `next build` — env vars may not be available yet
 78→  if (process.env.NEXT_PHASE === 'phase-production-build') return
 79→
 80→  const count = (dbConn.prepare('SELECT COUNT(*) as count FROM users').get() as CountRow).count
 81→  if (count > 0) return
 82→
 83→  const username = process.env.AUTH_USER || 'admin'
 84→  const password = process.env.AUTH_PASS || 'admin'
 85→  const displayName = username.charAt(0).toUpperCase() + username.slice(1)
 86→
 87→  dbConn.prepare(`
 88→    INSERT OR IGNORE INTO users (username, display_name, password_hash, role)
 89→    VALUES (?, ?, ?, ?)
 90→  `).run(username, displayName, hashPassword(password), 'admin')
 91→
 92→  logger.info(`Seeded admin user: ${username}`)
 93→}
