  1→import { NextRequest, NextResponse } from 'next/server';
  2→import { getDatabase, Agent, db_helpers } from '@/lib/db';
  3→import { eventBus } from '@/lib/event-bus';
  4→import { getTemplate, buildAgentConfig } from '@/lib/agent-templates';
  5→import { writeAgentToConfig, enrichAgentConfigFromWorkspace } from '@/lib/agent-sync';
  6→import { logAuditEvent } from '@/lib/db';
  7→import { requireRole } from '@/lib/auth';
  8→import { mutationLimiter } from '@/lib/rate-limit';
  9→import { logger } from '@/lib/logger';
 10→import { validateBody, createAgentSchema } from '@/lib/validation';
 11→
 12→/**
 13→ * GET /api/agents - List all agents with optional filtering
 14→ * Query params: status, role, limit, offset
 15→ */
 16→export async function GET(request: NextRequest) {
 17→  const auth = requireRole(request, 'viewer')
 18→  if ('error' in auth) return NextResponse.json({ error: auth.error }, { status: auth.status })
 19→
 20→  try {
 21→    const db = getDatabase();
 22→    const { searchParams } = new URL(request.url);
 23→    const workspaceId = auth.user.workspace_id ?? 1;
 24→    
 25→    // Parse query parameters
 26→    const status = searchParams.get('status');
 27→    const role = searchParams.get('role');
 28→    const limit = Math.min(parseInt(searchParams.get('limit') || '50'), 200);
 29→    const offset = parseInt(searchParams.get('offset') || '0');
 30→    
 31→    // Build dynamic query
 32→    let query = 'SELECT * FROM agents WHERE workspace_id = ?';
 33→    const params: any[] = [workspaceId];
 34→    
 35→    if (status) {
 36→      query += ' AND status = ?';
 37→      params.push(status);
 38→    }
 39→    
 40→    if (role) {
 41→      query += ' AND role = ?';
 42→      params.push(role);
 43→    }
 44→    
 45→    query += ' ORDER BY created_at DESC LIMIT ? OFFSET ?';
 46→    params.push(limit, offset);
 47→    
 48→    const stmt = db.prepare(query);
 49→    const agents = stmt.all(...params) as Agent[];
 50→    
 51→    // Parse JSON config field
 52→    const agentsWithParsedData = agents.map(agent => ({
 53→      ...agent,
 54→      config: enrichAgentConfigFromWorkspace(agent.config ? JSON.parse(agent.config) : {})
 55→    }));
 56→    
 57→    // Get task counts for each agent (prepare once, reuse per agent)
 58→    const taskCountStmt = db.prepare(`
 59→      SELECT
 60→        COUNT(*) as total,
 61→        SUM(CASE WHEN status = 'assigned' THEN 1 ELSE 0 END) as assigned,
 62→        SUM(CASE WHEN status = 'in_progress' THEN 1 ELSE 0 END) as in_progress,
 63→        SUM(CASE WHEN status = 'done' THEN 1 ELSE 0 END) as completed
 64→      FROM tasks
 65→      WHERE assigned_to = ? AND workspace_id = ?
 66→    `);
 67→
 68→    const agentsWithStats = agentsWithParsedData.map(agent => {
 69→      const taskStats = taskCountStmt.get(agent.name, workspaceId) as any;
 70→
 71→      return {
 72→        ...agent,
 73→        taskStats: {
 74→          total: taskStats.total || 0,
 75→          assigned: taskStats.assigned || 0,
 76→          in_progress: taskStats.in_progress || 0,
 77→          completed: taskStats.completed || 0
 78→        }
 79→      };
 80→    });
 81→    
 82→    // Get total count for pagination
 83→    let countQuery = 'SELECT COUNT(*) as total FROM agents WHERE workspace_id = ?';
 84→    const countParams: any[] = [workspaceId];
 85→    if (status) {
 86→      countQuery += ' AND status = ?';
 87→      countParams.push(status);
 88→    }
 89→    if (role) {
 90→      countQuery += ' AND role = ?';
 91→      countParams.push(role);
 92→    }
 93→    const countRow = db.prepare(countQuery).get(...countParams) as { total: number };
 94→
 95→    return NextResponse.json({
 96→      agents: agentsWithStats,
 97→      total: countRow.total,
 98→      page: Math.floor(offset / limit) + 1,
 99→      limit
100→    });
101→  } catch (error) {
102→    logger.error({ err: error }, 'GET /api/agents error');
103→    return NextResponse.json({ error: 'Failed to fetch agents' }, { status: 500 });
104→  }
105→}
