107→/**
108→ * POST /api/agents - Create a new agent
109→ */
110→export async function POST(request: NextRequest) {
111→  const auth = requireRole(request, 'operator');
112→  if ('error' in auth) return NextResponse.json({ error: auth.error }, { status: auth.status });
113→
114→  const rateCheck = mutationLimiter(request);
115→  if (rateCheck) return rateCheck;
116→
117→  try {
118→    const db = getDatabase();
119→    const workspaceId = auth.user.workspace_id ?? 1;
120→    const validated = await validateBody(request, createAgentSchema);
121→    if ('error' in validated) return validated.error;
122→    const body = validated.data;
123→
124→    const {
125→      name,
126→      role,
127→      session_key,
128→      soul_content,
129→      status = 'offline',
130→      config = {},
131→      template,
132→      gateway_config,
133→      write_to_gateway
134→    } = body;
135→
136→    // Resolve template if specified
137→    let finalRole = role;
138→    let finalConfig: Record<string, any> = { ...config };
139→    if (template) {
140→      const tpl = getTemplate(template);
141→      if (tpl) {
142→        const builtConfig = buildAgentConfig(tpl, (gateway_config || {}) as any);
143→        finalConfig = { ...builtConfig, ...finalConfig };
144→        if (!finalRole) finalRole = tpl.config.identity?.theme || tpl.type;
145→      }
146→    } else if (gateway_config) {
147→      finalConfig = { ...finalConfig, ...(gateway_config as Record<string, any>) };
148→    }
149→
150→    if (!name || !finalRole) {
151→      return NextResponse.json({ error: 'Name and role are required' }, { status: 400 });
152→    }
153→
154→    // Check if agent name already exists
155→    const existingAgent = db
156→      .prepare('SELECT id FROM agents WHERE name = ? AND workspace_id = ?')
157→      .get(name, workspaceId);
158→    if (existingAgent) {
159→      return NextResponse.json({ error: 'Agent name already exists' }, { status: 409 });
160→    }
161→    
162→    const now = Math.floor(Date.now() / 1000);
163→    
164→    const stmt = db.prepare(`
165→      INSERT INTO agents (
166→        name, role, session_key, soul_content, status, 
167→        created_at, updated_at, config, workspace_id
168→      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
169→    `);
170→    
171→    const dbResult = stmt.run(
172→      name,
173→      finalRole,
174→      session_key,
175→      soul_content,
176→      status,
177→      now,
178→      now,
179→      JSON.stringify(finalConfig),
180→      workspaceId
181→    );
182→
183→    const agentId = dbResult.lastInsertRowid as number;
184→    
185→    // Log activity
186→    db_helpers.logActivity(
187→      'agent_created',
188→      'agent',
189→      agentId,
190→      auth.user.username,
191→      `Created agent: ${name} (${finalRole})${template ? ` from template: ${template}` : ''}`,
192→      {
193→        name,
194→        role: finalRole,
195→        status,
196→        session_key,
197→        template: template || null
198→      },
199→      workspaceId
200→    );
201→    
202→    // Fetch the created agent
203→    const createdAgent = db
204→      .prepare('SELECT * FROM agents WHERE id = ? AND workspace_id = ?')
205→      .get(agentId, workspaceId) as Agent;
206→    const parsedAgent = {
207→      ...createdAgent,
208→      config: JSON.parse(createdAgent.config || '{}'),
209→      taskStats: { total: 0, assigned: 0, in_progress: 0, completed: 0 }
210→    };
