259→export async function PUT(request: NextRequest) {
260→  const auth = requireRole(request, 'operator');
261→  if ('error' in auth) return NextResponse.json({ error: auth.error }, { status: auth.status });
262→
263→  const rateCheck = mutationLimiter(request);
264→  if (rateCheck) return rateCheck;
265→
266→  try {
267→    const db = getDatabase();
268→    const workspaceId = auth.user.workspace_id ?? 1;
269→    const body = await request.json();
270→
271→    // Handle single agent update or bulk updates
272→    if (body.name) {
273→      // Single agent update
274→      const { name, status, last_activity, config, session_key, soul_content, role } = body;
275→      
276→      const agent = db
277→        .prepare('SELECT * FROM agents WHERE name = ? AND workspace_id = ?')
278→        .get(name, workspaceId) as Agent;
279→      if (!agent) {
280→        return NextResponse.json({ error: 'Agent not found' }, { status: 404 });
281→      }
282→      
283→      const now = Math.floor(Date.now() / 1000);
284→      
285→      // Build dynamic update query
286→      const fieldsToUpdate = [];
287→      const params: any[] = [];
288→      
289→      if (status !== undefined) {
290→        fieldsToUpdate.push('status = ?');
291→        params.push(status);
292→        
293→        fieldsToUpdate.push('last_seen = ?');
294→        params.push(now);
295→      }
296→      
297→      if (last_activity !== undefined) {
298→        fieldsToUpdate.push('last_activity = ?');
299→        params.push(last_activity);
300→      }
301→      
302→      if (config !== undefined) {
303→        fieldsToUpdate.push('config = ?');
304→        params.push(JSON.stringify(config));
305→      }
306→      
307→      if (session_key !== undefined) {
308→        fieldsToUpdate.push('session_key = ?');
309→        params.push(session_key);
310→      }
311→      
312→      if (soul_content !== undefined) {
313→        fieldsToUpdate.push('soul_content = ?');
314→        params.push(soul_content);
315→      }
316→      
317→      if (role !== undefined) {
318→        fieldsToUpdate.push('role = ?');
319→        params.push(role);
320→      }
321→      
322→      fieldsToUpdate.push('updated_at = ?');
323→      params.push(now);
324→      params.push(name, workspaceId);
325→      
326→      if (fieldsToUpdate.length === 1) { // Only updated_at
327→        return NextResponse.json({ error: 'No fields to update' }, { status: 400 });
328→      }
329→      
330→      const stmt = db.prepare(`
331→        UPDATE agents 
332→        SET ${fieldsToUpdate.join(', ')}
333→        WHERE name = ? AND workspace_id = ?
334→      `);
335→      
336→      stmt.run(...params);
337→      
338→      // Log status change if status was updated
339→      if (status !== undefined && status !== agent.status) {
340→        db_helpers.logActivity(
341→          'agent_status_change',
342→          'agent',
343→          agent.id,
344→          name,
345→          `Agent status changed from ${agent.status} to ${status}`,
346→          {
347→            oldStatus: agent.status,
348→            newStatus: status,
349→            last_activity
350→          },
351→          workspaceId
352→        );
353→      }
354→
355→      // Broadcast update to SSE clients
356→      eventBus.broadcast('agent.updated', {
357→        id: agent.id,
358→        name,
359→        ...(status !== undefined && { status }),
360→        ...(last_activity !== undefined && { last_activity }),
361→        ...(role !== undefined && { role }),
362→        updated_at: now,
363→      });
364→
365→      return NextResponse.json({ success: true });
366→    } else {
367→      return NextResponse.json({ error: 'Agent name is required' }, { status: 400 });
368→    }
369→  } catch (error) {
370→    logger.error({ err: error }, 'PUT /api/agents error');
371→    return NextResponse.json({ error: 'Failed to update agent' }, { status: 500 });
372→  }
373→}
