 65→function parseIdentityFromFile(content: string): { name?: string; theme?: string; emoji?: string; content?: string } {
 66→  if (!content.trim()) return {}
 67→  const lines = content.split('\n').map((line) => line.trim()).filter(Boolean)
 68→  let name: string | undefined
 69→  let theme: string | undefined
 70→  let emoji: string | undefined
 71→
 72→  for (const line of lines) {
 73→    if (!name && line.startsWith('#')) {
 74→      name = line.replace(/^#+\s*/, '').trim()
 75→      continue
 76→    }
 77→
 78→    if (!theme) {
 79→      const themeMatch = line.match(/^theme\s*:\s*(.+)$/i)
 80→      if (themeMatch?.[1]) {
 81→        theme = themeMatch[1].trim()
 82→        continue
 83→      }
 84→    }
 85→
 86→    if (!emoji) {
 87→      const emojiMatch = line.match(/^emoji\s*:\s*(.+)$/i)
 88→      if (emojiMatch?.[1]) {
 89→        emoji = emojiMatch[1].trim()
 90→      }
 91→    }
 92→  }
 93→
 94→  return {
 95→    ...(name ? { name } : {}),
 96→    ...(theme ? { theme } : {}),
 97→    ...(emoji ? { emoji } : {}),
 98→    content: lines.slice(0, 8).join('\n'),
 99→  }
100→}
101→
102→function parseToolsFromFile(content: string): { allow?: string[]; raw?: string } {
103→  if (!content.trim()) return {}
104→
105→  const parsedTools = new Set<string>()
106→  for (const line of content.split('\n')) {
107→    const cleaned = line.trim()
108→    if (!cleaned || cleaned.startsWith('#')) continue
109→
110→    const listMatch = cleaned.match(/^[-*]\s+`?([^`]+?)`?\s*$/)
111→    if (listMatch?.[1]) {
112→      parsedTools.add(listMatch[1].trim())
113→      continue
114→    }
115→
116→    const inlineMatch = cleaned.match(/^`([^`]+)`$/)
117→    if (inlineMatch?.[1]) {
118→      parsedTools.add(inlineMatch[1].trim())
119→    }
120→  }
121→
122→  const allow = [...parsedTools].filter(Boolean)
123→  return {
124→    ...(allow.length > 0 ? { allow } : {}),
125→    raw: content.split('\n').map((line) => line.trim()).filter(Boolean).slice(0, 24).join('\n'),
126→  }
127→}
