134→/** Safely read a file from an agent's workspace directory */
135→function readWorkspaceFile(workspace: string | undefined, filename: string): string | null {
136→  if (!workspace || !config.openclawHome) return null
137→  try {
138→    const safeWorkspace = resolveWithin(config.openclawHome, workspace)
139→    const safePath = resolveWithin(safeWorkspace, filename)
140→    if (existsSync(safePath)) {
141→      return readFileSync(safePath, 'utf-8')
142→    }
143→  } catch (err) {
144→    logger.warn({ err, workspace, filename }, 'Failed to read workspace file')
145→  }
146→  return null
147→}
