149→export function enrichAgentConfigFromWorkspace(configData: any): any {
150→  if (!configData || typeof configData !== 'object') return configData
151→  const workspace = typeof configData.workspace === 'string' ? configData.workspace : undefined
152→  if (!workspace) return configData
153→
154→  const identityFile = readWorkspaceFile(workspace, 'identity.md')
155→  const toolsFile = readWorkspaceFile(workspace, 'TOOLS.md')
156→
157→  const mergedIdentity = {
158→    ...parseIdentityFromFile(identityFile || ''),
159→    ...((configData.identity && typeof configData.identity === 'object') ? configData.identity : {}),
160→  }
161→  const mergedTools = {
162→    ...parseToolsFromFile(toolsFile || ''),
163→    ...((configData.tools && typeof configData.tools === 'object') ? configData.tools : {}),
164→  }
165→
166→  return {
167→    ...configData,
168→    identity: Object.keys(mergedIdentity).length > 0 ? mergedIdentity : configData.identity,
169→    tools: Object.keys(mergedTools).length > 0 ? mergedTools : configData.tools,
170→  }
171→}
