  6→/**
  7→ * GET /api/agents/[id]/heartbeat - Agent heartbeat check
  8→ * 
  9→ * Checks for:
 10→ * - @mentions in recent comments
 11→ * - Assigned tasks
 12→ * - Recent activity feed items
 13→ * 
 14→ * Returns work items or "HEARTBEAT_OK" if nothing to do
 15→ */
 16→export async function GET(
 17→  request: NextRequest,
 18→  { params }: { params: Promise<{ id: string }> }
 19→) {
 20→  const auth = requireRole(request, 'viewer')
 21→  if ('error' in auth) return NextResponse.json({ error: auth.error }, { status: auth.status })
 22→
 23→  try {
 24→    const db = getDatabase();
 25→    const resolvedParams = await params;
 26→    const agentId = resolvedParams.id;
 27→    const workspaceId = auth.user.workspace_id ?? 1;
 28→    
 29→    // Get agent by ID or name
 30→    let agent: any;
 31→    if (isNaN(Number(agentId))) {
 32→      // Lookup by name
 33→      agent = db.prepare('SELECT * FROM agents WHERE name = ? AND workspace_id = ?').get(agentId, workspaceId);
 34→    } else {
 35→      // Lookup by ID
 36→      agent = db.prepare('SELECT * FROM agents WHERE id = ? AND workspace_id = ?').get(Number(agentId), workspaceId);
 37→    }
 38→    
 39→    if (!agent) {
 40→      return NextResponse.json({ error: 'Agent not found' }, { status: 404 });
 41→    }
 42→    
 43→    const workItems: any[] = [];
 44→    const now = Math.floor(Date.now() / 1000);
 45→    const fourHoursAgo = now - (4 * 60 * 60); // Check last 4 hours
 46→    
 47→    // 1. Check for @mentions in recent comments
 48→    const mentions = db.prepare(`
 49→      SELECT c.*, t.title as task_title 
 50→      FROM comments c
 51→      JOIN tasks t ON c.task_id = t.id
 52→      WHERE c.mentions LIKE ?
 53→      AND c.workspace_id = ?
 54→      AND t.workspace_id = ?
 55→      AND c.created_at > ?
 56→      ORDER BY c.created_at DESC
 57→      LIMIT 10
 58→    `).all(`%"${agent.name}"%`, workspaceId, workspaceId, fourHoursAgo);
 59→    
 60→    if (mentions.length > 0) {
 61→      workItems.push({
 62→        type: 'mentions',
 63→        count: mentions.length,
 64→        items: mentions.map((m: any) => ({
 65→          id: m.id,
 66→          task_title: m.task_title,
 67→          author: m.author,
 68→          content: m.content.substring(0, 100) + '...',
 69→          created_at: m.created_at
 70→        }))
 71→      });
 72→    }
 73→    
 74→    // 2. Check for assigned tasks
 75→    const assignedTasks = db.prepare(`
 76→      SELECT * FROM tasks 
 77→      WHERE assigned_to = ?
 78→      AND workspace_id = ?
 79→      AND status IN ('assigned', 'in_progress')
 80→      ORDER BY priority DESC, created_at ASC
 81→      LIMIT 10
 82→    `).all(agent.name, workspaceId);
 83→    
 84→    if (assignedTasks.length > 0) {
 85→      workItems.push({
 86→        type: 'assigned_tasks',
 87→        count: assignedTasks.length,
 88→        items: assignedTasks.map((t: any) => ({
 89→          id: t.id,
 90→          title: t.title,
 91→          status: t.status,
 92→          priority: t.priority,
 93→          due_date: t.due_date
 94→        }))
 95→      });
 96→    }
 97→    
 98→    // 3. Check for unread notifications
 99→    const notifications = db_helpers.getUnreadNotifications(agent.name, workspaceId);
100→    
101→    if (notifications.length > 0) {
102→      workItems.push({
103→        type: 'notifications',
104→        count: notifications.length,
105→        items: notifications.slice(0, 5).map(n => ({
106→          id: n.id,
107→          type: n.type,
108→          title: n.title,
109→          message: n.message,
110→          created_at: n.created_at
111→        }))
112→      });
113→    }
114→    
115→    // 4. Check for urgent activities that might need attention
116→    const urgentActivities = db.prepare(`
117→      SELECT * FROM activities 
118→      WHERE type IN ('task_created', 'task_assigned', 'high_priority_alert')
119→      AND workspace_id = ?
120→      AND created_at > ?
121→      AND description LIKE ?
122→      ORDER BY created_at DESC
123→      LIMIT 5
124→    `).all(workspaceId, fourHoursAgo, `%${agent.name}%`);
125→    
126→    if (urgentActivities.length > 0) {
127→      workItems.push({
128→        type: 'urgent_activities',
129→        count: urgentActivities.length,
130→        items: urgentActivities.map((a: any) => ({
131→          id: a.id,
132→          type: a.type,
133→          description: a.description,
134→          created_at: a.created_at
135→        }))
136→      });
137→    }
138→    
139→    // Update agent last_seen and status to show heartbeat activity
140→    db_helpers.updateAgentStatus(agent.name, 'idle', 'Heartbeat check', workspaceId);
141→    
142→    // Log heartbeat activity
143→    db_helpers.logActivity(
144→      'agent_heartbeat',
145→      'agent',
146→      agent.id,
147→      agent.name,
148→      `Heartbeat check completed - ${workItems.length > 0 ? `${workItems.length} work items found` : 'no work items'}`,
149→      { workItemsCount: workItems.length, workItemTypes: workItems.map(w => w.type) },
150→      workspaceId
151→    );
152→    
153→    if (workItems.length === 0) {
154→      return NextResponse.json({
155→        status: 'HEARTBEAT_OK',
156→        agent: agent.name,
157→        checked_at: now,
158→        message: 'No work items found'
159→      });
160→    }
161→    
162→    return NextResponse.json({
163→      status: 'WORK_ITEMS_FOUND',
164→      agent: agent.name,
165→      checked_at: now,
166→      work_items: workItems,
167→      total_items: workItems.reduce((sum, item) => sum + item.count, 0)
168→    });
169→    
170→  } catch (error) {
171→    logger.error({ err: error }, 'GET /api/agents/[id]/heartbeat error');
172→    return NextResponse.json({ error: 'Failed to perform heartbeat check' }, { status: 500 });
173→  }
174→}
