176→/**
177→ * POST /api/agents/[id]/heartbeat - Enhanced heartbeat
178→ *
179→ * Accepts optional body:
180→ * - connection_id: update direct_connections.last_heartbeat
181→ * - status: agent status override
182→ * - last_activity: activity description
183→ * - token_usage: { model, inputTokens, outputTokens } for inline token reporting
184→ */
185→export async function POST(
186→  request: NextRequest,
187→  { params }: { params: Promise<{ id: string }> }
188→) {
189→  const auth = requireRole(request, 'operator');
190→  if ('error' in auth) return NextResponse.json({ error: auth.error }, { status: auth.status });
191→
192→  let body: any = {};
193→  try {
194→    body = await request.json();
195→  } catch {
196→    // No body is fine — fall through to standard heartbeat
197→  }
198→
199→  const { connection_id, token_usage } = body;
200→  const db = getDatabase();
201→  const now = Math.floor(Date.now() / 1000);
202→  const workspaceId = auth.user.workspace_id ?? 1;
203→
204→  // Update direct connection heartbeat if connection_id provided
205→  if (connection_id) {
206→    db.prepare('UPDATE direct_connections SET last_heartbeat = ?, updated_at = ? WHERE connection_id = ? AND status = ? AND workspace_id = ?')
207→      .run(now, now, connection_id, 'connected', workspaceId);
208→  }
209→
210→  // Inline token reporting
211→  let tokenRecorded = false;
212→  if (token_usage && token_usage.model && token_usage.inputTokens != null && token_usage.outputTokens != null) {
213→    const resolvedParams = await params;
214→    const agentId = resolvedParams.id;
215→    let agent: any;
216→    if (isNaN(Number(agentId))) {
217→      agent = db.prepare('SELECT * FROM agents WHERE name = ? AND workspace_id = ?').get(agentId, workspaceId);
218→    } else {
219→      agent = db.prepare('SELECT * FROM agents WHERE id = ? AND workspace_id = ?').get(Number(agentId), workspaceId);
220→    }
221→
222→    if (agent) {
223→      const sessionId = `${agent.name}:cli`;
224→      db.prepare(
225→        `INSERT INTO token_usage (model, session_id, input_tokens, output_tokens, created_at)
226→         VALUES (?, ?, ?, ?, ?)`
227→      ).run(token_usage.model, sessionId, token_usage.inputTokens, token_usage.outputTokens, now);
228→      tokenRecorded = true;
229→    }
230→  }
231→
232→  // Reuse GET logic for work-items check, then augment response
233→  const getResponse = await GET(request, { params });
234→  const getBody = await getResponse.json();
235→
236→  return NextResponse.json({
237→    ...getBody,
238→    token_recorded: tokenRecorded,
239→  });
240→}
